import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    if not unvisited_customers:
        return None

    distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])
    depot_distances = np.array([distance(depot_pos, customer) for customer in unvisited_customers])
    num_idle_trucks = np.zeros(len(unvisited_customers))

    for i, customer in enumerate(unvisited_customers):
        num_idle_trucks[i] = sum(distance(truck_pos, customer) < distance(cur_truck_pos, customer)
                                 for truck_pos in all_truck_pos)

    # Dynamic adjustment of weights based on real-time metrics
    proximity_weight = 4.0  # Importance of being near current truck position
    idle_truck_weight = 2.5 * np.mean(num_idle_trucks)  # Enhancement if fewer idle trucks nearby
    depot_weight = 1.0  # Encourages return towards the depot strategically

    scores = proximity_weight * distances + idle_truck_weight * num_idle_trucks - depot_weight * depot_distances
    best_node = np.argmin(scores)

    return best_node
